INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23d28c3b-3aa3-40e9-b0fb-cf38992ebbdb', $q$Built-in plagiarism checker$q$, $q$Flags matching content and shows the source it overlaps with.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23d28c3b-3aa3-40e9-b0fb-cf38992ebbdb', $q$Tone changer and rewriter$q$, $q$Adjusts the tone of existing text or rewrites it while preserving meaning.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23d28c3b-3aa3-40e9-b0fb-cf38992ebbdb', $q$Ad copy and product description generation$q$, $q$Templates aimed specifically at e-commerce and advertising copy needs.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('23d28c3b-3aa3-40e9-b0fb-cf38992ebbdb', $q$Multi-language support$q$, $q$Supports content generation in around 110 languages.$q$, 7);
