INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('23d28c3b-3aa3-40e9-b0fb-cf38992ebbdb', $q$Built-in plagiarism checking without needing a separate tool$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('23d28c3b-3aa3-40e9-b0fb-cf38992ebbdb', $q$Output quality on longer articles often needs human editing before publishing$q$, 0);
